function mdToConfluenceHtml(md) {
  const lines = md.replace(/\r/g, '').split('\n');
  let html = '', inCodeBlock = false, codeContent = '', codeLang = 'text', inList = false;
  // Escape XML special chars in text BEFORE applying inline markdown, otherwise a bare
  // & / < / > in prose (e.g. "Andrew Hunt & David Thomas") produces invalid storage XML,
  // which Confluence rejects with the misleading "Content contains unsupported extensions".
  function fmt(t) { t = t.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); return t.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>').replace(/\*(.+?)\*/g, '<em>$1</em>').replace(/`([^`]+)`/g, '<code>$1</code>').replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>'); }
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (line.startsWith('```') && !inCodeBlock) { if (inList) { html += '</ul>'; inList = false; } inCodeBlock = true; codeLang = line.slice(3).trim() || 'text'; codeContent = ''; continue; }
    if (line.startsWith('```') && inCodeBlock) { inCodeBlock = false; html += '<ac:structured-macro ac:name="code"><ac:parameter ac:name="language">' + codeLang + '</ac:parameter><ac:plain-text-body><![CDATA[' + codeContent.trim() + ']]></ac:plain-text-body></ac:structured-macro>'; continue; }
    if (inCodeBlock) { codeContent += line + '\n'; continue; }
    if (line.match(/^\|.+\|$/) && i + 1 < lines.length && lines[i+1].match(/^\|[-| :]+\|$/)) {
      if (inList) { html += '</ul>'; inList = false; }
      const headers = line.split('|').filter(c => c.trim()).map(c => '<th>' + fmt(c.trim()) + '</th>').join('');
      html += '<table><thead><tr>' + headers + '</tr></thead><tbody>'; i++;
      while (i + 1 < lines.length && lines[i+1].match(/^\|.+\|$/)) { i++; html += '<tr>' + lines[i].split('|').filter(c => c.trim()).map(c => '<td>' + fmt(c.trim()) + '</td>').join('') + '</tr>'; }
      html += '</tbody></table>'; continue;
    }
    const hm = line.match(/^(#{1,6}) (.+)$/);
    if (hm) { if (inList) { html += '</ul>'; inList = false; } html += '<h' + hm[1].length + '>' + fmt(hm[2]) + '</h' + hm[1].length + '>'; continue; }
    if (line.match(/^---+$/)) { if (inList) { html += '</ul>'; inList = false; } html += '<hr/>'; continue; }
    if (line.startsWith('> ')) { if (inList) { html += '</ul>'; inList = false; } html += '<blockquote><p>' + fmt(line.slice(2)) + '</p></blockquote>'; continue; }
    if (line.match(/^- \[([ xX])\] /)) {
      if (inList) { html += '</ul>'; inList = false; }
      html += '<ac:task-list>';
      while (i < lines.length && lines[i].match(/^- \[([ xX])\] /)) { const cm = lines[i].match(/^- \[([ xX])\] (.+)/); html += '<ac:task><ac:task-status>' + ((cm[1]==='x'||cm[1]==='X') ? 'complete' : 'incomplete') + '</ac:task-status><ac:task-body>' + fmt(cm[2]) + '</ac:task-body></ac:task>'; i++; }
      html += '</ac:task-list>'; continue;
    }
    if (line.match(/^[-*] /)) { if (!inList) { html += '<ul>'; inList = true; } html += '<li>' + fmt(line.replace(/^[-*] /, '')) + '</li>'; continue; }
    if (line.trim() === '') { if (inList) { html += '</ul>'; inList = false; } continue; }
    if (inList) { html += '</ul>'; inList = false; }
    html += '<p>' + fmt(line) + '</p>';
  }
  if (inList) html += '</ul>';
  return html;
}

function extractPageId(val) { if (!val) return ''; val = val.trim(); const m = val.match(/\/pages\/(\d+)/); if (m) return m[1]; return val.match(/^\d+$/) ? val : val; }

const body = $input.first().json.body;
const pages = body.pages || [];
const labelsStr = body.labels || '';
let parentPageId = extractPageId(body.parentPageId || '') || ($env.CONFLUENCE_PARENT_PAGE_ID || '');
const date = new Date().toISOString().split('T')[0];
const labels = ['n8n-pipeline-generated'];
if (labelsStr) labels.push(...labelsStr.split(',').map(l => l.trim()).filter(Boolean));
const labelsJson = labels.map(l => ({ prefix: 'global', name: l }));

if (pages.length === 0 && body.pageMarkdown) {
  pages.push({ markdown: body.pageMarkdown, pageId: body.pageId || '', title: body.title || '' });
  const sms = body.sectionMarkdowns || []; for (const s of sms) { if (s.trim()) pages[0].markdown += '\n\n---\n\n' + s; }
}
if (pages.length === 0) return [{ json: { error: 'No pages provided' } }];

// Process ALL pages sequentially in this single Code node.
// For creates: build POST body. For updates: fetch version via API then build PUT body.
const confBase = $env.CONFLUENCE_BASE_URL;
const spaceKey = $env.CONFLUENCE_SPACE_KEY;
const results = [];

for (let idx = 0; idx < pages.length; idx++) {
  const pg = pages[idx];
  const md = pg.markdown || '';
  const pageId = extractPageId(pg.pageId || '');
  let title = pg.title || '';
  if (!title) { const tm = md.replace(/\r/g, '').match(/^# (.+)$/m); title = tm ? tm[1] : 'Page ' + (idx + 1); }
  let html = mdToConfluenceHtml(md);
  html += '<hr/><p><em>Published from markdown by <a href="https://github.com/openmindednewby/ai-confluence-pipeline">ai-confluence-pipeline</a> on ' + date + '</em></p>';

  if (pageId) {
    // Update: output GET request first, then PUT
    results.push({ json: { step: 'get-version', pageId, title, html, pageIndex: idx, method: 'GET', url: confBase + '/wiki/rest/api/content/' + pageId + '?expand=version', apiBody: null, isUpdate: true } });
  } else {
    // Create: output POST body
    const confBody = { type: 'page', title, space: { key: spaceKey }, body: { storage: { value: html, representation: 'storage' } }, metadata: { labels: labelsJson } };
    if (parentPageId) confBody.ancestors = [{ id: parentPageId }];
    results.push({ json: { step: 'create', pageId: '', title, html, pageIndex: idx, method: 'POST', url: confBase + '/wiki/rest/api/content', apiBody: confBody, isUpdate: false } });
  }
}

return results;

// For each update item: get the version from HTTP response, get our data from the matching Prepare Pages item
const versionResponses = $input.all();
const prepItems = $('Needs Version?').all();

return versionResponses.map((vr, i) => {
  const currentVersion = vr.json.version?.number || 1;
  const prep = prepItems[i]?.json || {};
  const updateBody = {
    type: 'page',
    title: prep.title,
    space: { key: $env.CONFLUENCE_SPACE_KEY },
    body: { storage: { value: prep.html, representation: 'storage' } },
    version: { number: currentVersion + 1 }
  };
  return { json: { method: 'PUT', url: $env.CONFLUENCE_BASE_URL + '/wiki/rest/api/content/' + prep.pageId, apiBody: updateBody, title: prep.title, pageId: prep.pageId, isUpdate: true, pageIndex: prep.pageIndex } };
});

const allPrepped = $('Prepare Pages').all();
const allResults = $input.all();

const pages = allPrepped.map((prep, i) => {
  const result = allResults[i]?.json || {};
  const url = (result._links?.base || '') + (result._links?.webui || '');
  return {
    id: result.id || prep.json.pageId,
    title: prep.json.title,
    url: url,
    action: prep.json.isUpdate ? 'updated' : 'created'
  };
});

return [{ json: { success: true, pages, pageCount: pages.length } }];
